import React, { useEffect, useState } from "react";
import { Table, Button, Space, Input, Tooltip } from "antd";
import {
  Edit3,
  Trash2,
  Search,
  Plus,
  FolderTree,
  Activity,
  ShieldCheck,
  Layers,
  Hash,
  Box,
  Pencil,
  Zap,
  ArrowRight
} from "lucide-react";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { toast } from "react-toastify";
import {
  deleteAProductSubCategory,
  getSubCategories,
  resetState,
} from "../features/pSubCategory/pSubCategorySlice";
import CustomModal from "../components/CustomModal";

const Subcategorylist = () => {
  const [open, setOpen] = useState(false);
  const [pCatId, setpCatId] = useState("");
  const [searchText, setSearchText] = useState("");

  const showModal = (e) => {
    setOpen(true);
    setpCatId(e);
  };

  const hideModal = () => {
    setOpen(false);
  };

  const dispatch = useDispatch();
  useEffect(() => {
    dispatch(resetState());
    dispatch(getSubCategories());
  }, [dispatch]);

  const pSubCatStat = useSelector((state) => state.pSubcategory.pSubCategories);

  const columns = [
    {
      title: "Archetype Protocol",
      dataIndex: "name",
      render: (text) => (
        <div className="flex items-center gap-4 group cursor-default">
          <div className="w-12 h-12 rounded-[18px] bg-slate-50 border border-slate-100 flex items-center justify-center text-slate-400 group-hover:bg-blue-600 group-hover:text-white transition-all duration-500 shadow-sm shadow-slate-200/50">
            <FolderTree size={20} />
          </div>
          <div className="flex flex-col">
            <span className="text-[15px] font-black text-slate-900 leading-tight group-hover:text-blue-600 transition-colors uppercase tracking-tight">{text}</span>
            <span className="text-[11px] text-slate-400 font-bold uppercase tracking-widest mt-1 italic">Ontological Extension</span>
          </div>
        </div>
      ),
      sorter: (a, b) => a.name?.localeCompare(b.name),
    },
    {
      title: "Sub-Registry Hash",
      dataIndex: "key",
      width: 180,
      render: (text) => (
        <div className="flex items-center gap-2">
           <Hash size={12} className="text-slate-300" />
           <code className="text-[11px] font-black px-3 py-1.5 rounded-xl bg-slate-900 text-cyan-400 shadow-lg shadow-slate-900/10 uppercase tracking-widest">
            SUB-{String(text).padStart(3, "0")}
           </code>
        </div>
      ),
    },
    {
      title: "Operational Status",
      key: "status",
      width: 140,
      render: () => (
        <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-blue-50 text-blue-600 border border-blue-100/50 text-[10px] font-black uppercase tracking-widest">
           <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-pulse" />
           Active Node
        </div>
      ),
    },
    {
      title: "Terminal",
      width: 120,
      render: (_, record) => (
        <div className="flex items-center gap-3">
          <Link to={`../subcategory/${record._id}`}>
            <Tooltip title="Execute Revision">
              <Button
                type="text"
                icon={<Pencil size={16} />}
                className="w-10 h-10 flex items-center justify-center rounded-2xl bg-slate-50 border border-slate-100/50 text-slate-400 hover:text-blue-600 hover:bg-blue-50 transition-all active:scale-90"
              />
            </Tooltip>
          </Link>
          <Tooltip title="Purge Sequence">
             <Button
                type="text"
                danger
                icon={<Trash2 size={16} />}
                onClick={() => showModal(record._id)}
                className="w-10 h-10 flex items-center justify-center rounded-2xl bg-rose-50 border border-rose-100/50 text-rose-400 hover:text-rose-600 hover:bg-rose-100 transition-all active:scale-90"
              />
          </Tooltip>
        </div>
      ),
    },
  ];

  const data1 =
    pSubCatStat
      ?.filter(
        (s) =>
          !searchText ||
          (s.name || s.title).toLowerCase().includes(searchText.toLowerCase()),
      )
      .map((sub, i) => ({
        key: i + 1,
        id: sub.id || sub._id,
        _id: sub.id || sub._id,
        name: sub.name || sub.title,
      })) || [];


  const deleteCategory = (e) => {
    dispatch(deleteAProductSubCategory(e));
    toast.success("Archetype Purged Successfully");
    setOpen(false);
    setTimeout(() => {
      dispatch(getSubCategories());
    }, 1000);
  };

  return (
    <div className="space-y-12 pb-20 animate-in fade-in slide-in-from-bottom-6 duration-700">
      {/* Command Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8">
        <div className="space-y-2">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-1.5 h-4 rounded-full bg-cyan-600 animate-pulse" />
            <span className="text-[11px] font-black text-cyan-600 uppercase tracking-[0.3em]">Sub-Commercial Ontology</span>
          </div>
          <h1 className="text-[42px] font-black text-slate-900 tracking-tighter leading-none">
            Subcategory <span className="text-cyan-600">Registry</span>
          </h1>
          <p className="text-[16px] text-slate-400 font-bold max-w-xl">
            Surveillance and management of child product classification and extension nodes.
          </p>
        </div>
        
        <div className="flex items-center gap-4 w-full lg:w-auto">
          <div className="relative flex-1 lg:w-80">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
            <Input
              placeholder="Find archetype..."
              className="w-full h-14 pl-12 pr-6 bg-white border border-slate-100 rounded-[22px] focus:outline-none focus:ring-4 focus:ring-cyan-500/5 transition-all text-[15px] font-bold shadow-sm shadow-slate-200/40"
              onChange={(e) => setSearchText(e.target.value)}
            />
          </div>
          <Link to="../subcategory">
            <button className="h-14 px-8 bg-slate-900 hover:bg-cyan-600 text-white font-black uppercase text-[12px] tracking-[0.2em] rounded-[22px] shadow-xl shadow-slate-900/20 transition-all flex items-center gap-3 group active:scale-95">
              <Plus size={20} className="group-hover:rotate-90 transition-transform" /> Add Extension
            </button>
          </Link>
        </div>
      </div>

      {/* Analytics Matrix */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="enterprise-card p-10 flex items-center gap-6 border-l-4 border-l-cyan-500">
              <div className="w-16 h-16 rounded-[24px] bg-cyan-50 text-cyan-600 flex items-center justify-center shadow-inner">
                  <Layers size={32} />
              </div>
              <div>
                  <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Extensions Active</p>
                  <h4 className="text-[28px] font-black text-slate-900 tracking-tighter leading-none italic">{data1.length} Elements</h4>
              </div>
          </div>
          <div className="enterprise-card p-10 flex items-center gap-6 border-l-4 border-l-emerald-500">
              <div className="w-16 h-16 rounded-[24px] bg-emerald-50 text-emerald-600 flex items-center justify-center shadow-inner">
                  <Activity size={32} />
              </div>
              <div>
                  <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Network Pulse</p>
                  <h4 className="text-[28px] font-black text-slate-900 tracking-tighter leading-none italic">Active</h4>
              </div>
          </div>
          <div className="enterprise-card p-10 flex items-center gap-6 border-l-4 border-l-slate-900">
              <div className="w-16 h-16 rounded-[24px] bg-slate-900 text-white flex items-center justify-center shadow-inner">
                  <Zap size={32} />
              </div>
              <div>
                  <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Sync Rank</p>
                  <h4 className="text-[28px] font-black text-slate-900 tracking-tighter leading-none italic uppercase">Priority</h4>
              </div>
          </div>
      </div>

      <div className="bg-white rounded-[48px] border border-slate-100 overflow-hidden shadow-2xl shadow-slate-200/30 transition-all">
        <div className="p-10 border-b border-slate-50 flex items-center justify-between bg-slate-50/10">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 rounded-[18px] bg-slate-900 text-white flex items-center justify-center shadow-lg">
              <FolderTree size={24} />
            </div>
            <div>
              <h3 className="text-[18px] font-black text-slate-900 leading-none uppercase tracking-tighter italic">Sub-Extension Registry</h3>
              <p className="text-[12px] text-slate-400 font-bold mt-1 uppercase tracking-widest">Child nodes indexed within the commercial sector</p>
            </div>
          </div>
          <div className="flex items-center gap-2 bg-blue-50 px-4 py-2 rounded-2xl border border-blue-100">
            <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse" />
            <span className="text-[11px] font-black text-blue-600 uppercase tracking-widest">Registry Sync Nominal</span>
          </div>
        </div>
        
        <Table 
          columns={columns} 
          dataSource={data1} 
          pagination={{ pageSize: 12, className: "px-10 py-6 font-black" }} 
          className="super-modern-table" 
          rowKey="key" 
          scroll={{ x: 800 }}
        />
      </div>

      <CustomModal 
        hideModal={hideModal} 
        open={open} 
        performAction={() => deleteCategory(pCatId)}
        title="Protocol Termination Request" 
        content="This will purge the sub-extension from the active registry. Products mapped to this node may be orphaned. Confirm purge?" 
      />

      <style>{`
        .super-modern-table .ant-table-thead > tr > th {
            background: #fdfdfe !important;
            font-weight: 900 !important;
            font-size: 10px !important;
            color: #64748b !important;
            text-transform: uppercase !important;
            letter-spacing: 0.2em !important;
            border-bottom: 2px solid #f8fafc !important;
            padding: 30px 40px !important;
        }
        .super-modern-table .ant-table-tbody > tr > td {
            padding: 32px 40px !important;
            border-bottom: 1px solid #f1f5f9 !important;
            color: #1e293b !important;
            vertical-align: middle !important;
        }
        .enterprise-card {
           background: #ffffff;
           border-radius: 40px;
           border: 1.5px solid #f8fafc;
           box-shadow: 0 10px 30px rgba(0,0,0,0.02);
           transition: all 0.5s cubic-bezier(0.4, 0, 0.2, 1);
        }
        .enterprise-card:hover {
           transform: translateY(-5px);
           box-shadow: 0 20px 40px rgba(0,0,0,0.04);
           border-color: #e2e8f0;
        }
      `}</style>
    </div>
  );
};

export default Subcategorylist;
